SELECT ...
FROM ...
WHERE стовпчик = (SELECT стовпчик FROM ...);

SELECT name, city
FROM employees
WHERE city = (SELECT city FROM employees WHERE name = 'Іван Шевченко');

SELECT name, dept
FROM employees
WHERE dept IN (SELECT dept FROM employees WHERE city = 'Київ');

SELECT name, city
FROM employees
WHERE city NOT IN (SELECT city FROM employees WHERE dept = 'IT');

