SELECT колонки
FROM   таблиця_а
JOIN   таблиця_б ON таблиця_а.ключ = таблиця_б.ключ;

SELECT tracks.name, albums.title
FROM   tracks
JOIN   albums ON tracks.album_id = albums.id;

SELECT t.name, a.title
FROM   tracks  AS t
JOIN   albums  AS a ON t.album_id = a.id;

SELECT колонки
FROM   таблиця_а
LEFT JOIN таблиця_б ON таблиця_а.ключ = таблиця_б.ключ;

SELECT колонки
FROM   таблиця_а
RIGHT JOIN таблиця_б ON таблиця_а.ключ = таблиця_б.ключ;

SELECT t.name AS track, a.title AS album
FROM   tracks AS t
RIGHT JOIN albums AS a ON t.album_id = a.id;
